WITH src AS (SELECT s.category AS setting_category, s.name AS setting_name, s.setting AS setting_value, s.unit AS setting_unit, s.context AS context, s.vartype AS variable_type, s.source AS setting_source, s.min_val AS min_value, s.max_val AS max_value, s.enumvals AS enum_values, s.boot_val AS boot_value, s.reset_val AS reset_value, s.sourcefile AS source_file, s.sourceline AS source_line, s.short_desc AS short_description, s.extra_desc AS extra_description, s.pending_restart AS pending_restart, CASE WHEN NOT s.source IN ('override', 'default') THEN 1 ELSE 0 END AS is_default FROM pg_settings AS s) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, CHR(34) || REPLACE(src.setting_category, CHR(34), CHR(39)) || CHR(34) AS setting_category, CHR(34) || REPLACE(src.setting_name, CHR(34), CHR(39)) || CHR(34) AS setting_name, CHR(34) || REPLACE(src.setting_value, CHR(34), CHR(39)) || CHR(34) AS setting_value, src.setting_unit, src.context, src.variable_type, src.setting_source, src.min_value, src.max_value, CHR(34) || REPLACE(CAST(src.enum_values AS TEXT), CHR(34), CHR(39)) || CHR(34) AS enum_values, CHR(34) || REPLACE(CAST(src.boot_value AS TEXT), CHR(34), CHR(39)) || CHR(34) AS boot_value, CHR(34) || REPLACE(CAST(src.reset_value AS TEXT), CHR(34), CHR(39)) || CHR(34) AS reset_value, src.source_file, src.source_line, src.short_description, src.extra_description, src.pending_restart, src.is_default FROM src